SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;
CREATE DATABASE IF NOT EXISTS `cenvi_audit`;
USE `cenvi_audit`;

DROP TABLE IF EXISTS `DANH_MUC`;
CREATE TABLE `DANH_MUC` (
  `DM_ID` int NOT NULL AUTO_INCREMENT,
  `Ten_Danh_Muc` varchar(255) DEFAULT NULL,
  `Share_Drive_Folder_ID` varchar(255) DEFAULT NULL,
  `Metadata` json DEFAULT NULL,
  PRIMARY KEY (`DM_ID`),
  KEY `ix_DANH_MUC_Ten_Danh_Muc` (`Ten_Danh_Muc`),
  KEY `ix_DANH_MUC_DM_ID` (`DM_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `MUC_CON`;
CREATE TABLE `MUC_CON` (
  `MC_ID` int NOT NULL AUTO_INCREMENT,
  `DM_ID` int DEFAULT NULL,
  `Ten_Muc_Con` varchar(255) DEFAULT NULL,
  `Ngay_Het_Hieu_Luc` datetime DEFAULT NULL,
  `Share_Drive_Folder_ID` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`MC_ID`),
  KEY `DM_ID` (`DM_ID`),
  KEY `ix_MUC_CON_MC_ID` (`MC_ID`),
  CONSTRAINT `MUC_CON_ibfk_1` FOREIGN KEY (`DM_ID`) REFERENCES `DANH_MUC` (`DM_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `PHAN_QUYEN_TRUY_CAP`;
CREATE TABLE `PHAN_QUYEN_TRUY_CAP` (
  `PQ_ID` int NOT NULL AUTO_INCREMENT,
  `TL_ID` int DEFAULT NULL,
  `ND_ID` int DEFAULT NULL,
  `Cap_Do_Truy_Cap` varchar(20) DEFAULT NULL,
  PRIMARY KEY (`PQ_ID`),
  KEY `TL_ID` (`TL_ID`),
  KEY `ix_PHAN_QUYEN_TRUY_CAP_PQ_ID` (`PQ_ID`),
  KEY `ix_PHAN_QUYEN_TRUY_CAP_ND_ID` (`ND_ID`),
  CONSTRAINT `PHAN_QUYEN_TRUY_CAP_ibfk_1` FOREIGN KEY (`TL_ID`) REFERENCES `TAI_LIEU` (`TL_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `PHIEN_BAN_TAI_LIEU`;
CREATE TABLE `PHIEN_BAN_TAI_LIEU` (
  `PB_ID` int NOT NULL AUTO_INCREMENT,
  `TL_ID` int DEFAULT NULL,
  `So_Phien_Ban` decimal(5,2) DEFAULT NULL,
  `Share_Drive_File_ID` varchar(255) DEFAULT NULL,
  `Ten_File_Tren_Drive` varchar(255) DEFAULT NULL,
  `Ngay_Tai_Len` datetime DEFAULT NULL,
  `Metadata` json DEFAULT NULL,
  PRIMARY KEY (`PB_ID`),
  KEY `ix_PHIEN_BAN_TAI_LIEU_PB_ID` (`PB_ID`),
  KEY `TL_ID` (`TL_ID`),
  CONSTRAINT `PHIEN_BAN_TAI_LIEU_ibfk_1` FOREIGN KEY (`TL_ID`) REFERENCES `TAI_LIEU` (`TL_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `TAI_LIEU`;
CREATE TABLE `TAI_LIEU` (
  `TL_ID` int NOT NULL AUTO_INCREMENT,
  `MC_ID` int DEFAULT NULL,
  `Tieu_De` varchar(255) DEFAULT NULL,
  `Ngay_Het_Hieu_Luc` datetime DEFAULT NULL,
  `Current_Version_ID` int DEFAULT NULL,
  `Metadata` json DEFAULT NULL,
  PRIMARY KEY (`TL_ID`),
  KEY `ix_TAI_LIEU_TL_ID` (`TL_ID`),
  KEY `Current_Version_ID` (`Current_Version_ID`),
  KEY `MC_ID` (`MC_ID`),
  CONSTRAINT `TAI_LIEU_ibfk_1` FOREIGN KEY (`Current_Version_ID`) REFERENCES `PHIEN_BAN_TAI_LIEU` (`PB_ID`),
  CONSTRAINT `TAI_LIEU_ibfk_2` FOREIGN KEY (`MC_ID`) REFERENCES `MUC_CON` (`MC_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `WORK_LINKS`;
CREATE TABLE `WORK_LINKS` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `des` varchar(1000) DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_WORK_LINKS_id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `audit_sessions`;
CREATE TABLE `audit_sessions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `folder_id` int DEFAULT NULL,
  `category` varchar(50) DEFAULT NULL,
  `period` varchar(20) DEFAULT NULL,
  `year` int DEFAULT NULL,
  `status` varchar(20) DEFAULT NULL,
  `checklist_data` json DEFAULT NULL,
  `overall_note` text,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_audit_sessions_id` (`id`),
  KEY `ix_audit_sessions_folder_id` (`folder_id`)
) ENGINE=InnoDB AUTO_INCREMENT=243 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `companies`;
CREATE TABLE `companies` (
  `id` int NOT NULL AUTO_INCREMENT,
  `code` varchar(100) NOT NULL,
  `name` varchar(255) NOT NULL,
  `mst` varchar(100) DEFAULT NULL,
  `emails` json DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `employees`;
CREATE TABLE `employees` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `title` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `status` varchar(50) DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `folder_permissions`;
CREATE TABLE `folder_permissions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `folder_id` int NOT NULL,
  `email` varchar(255) NOT NULL,
  `role` varchar(50) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


DROP TABLE IF EXISTS `folders`;
CREATE TABLE `folders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `company_code` varchar(100) NOT NULL,
  `company_name` varchar(255) NOT NULL,
  `mst` varchar(100) DEFAULT NULL,
  `manager_employee_id` int DEFAULT NULL,
  `year` int DEFAULT NULL,
  `template` varchar(100) DEFAULT NULL,
  `status` varchar(50) DEFAULT NULL,
  `root_folder_id` varchar(255) DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=253 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


SET FOREIGN_KEY_CHECKS=1;
